import numpy as np

def sarsa_lambda_acrobot(
    features: list,
    rewards: list,
    num_weights: int,
    alpha: float,
    gamma: float,
    lam: float,
    initial_weights: np.ndarray,
    trace_type: str = "accumulating"
) -> list:
    w = initial_weights.copy().astype(float)
    z = [0.0] * num_weights
    T = len(rewards)

    for t in range(T):
        x_t = features[t]

        # Q(S_t, A_t) = w . x_t
        q_t = sum(w[i] for i in x_t)

        # Q(S_{t+1}, A_{t+1}) = 0 if terminal, else w . x_{t+1}
        if t == T - 1:
            q_next = 0.0
        else:
            x_next = features[t + 1]
            q_next = sum(w[i] for i in x_next)

        # TD error
        delta = rewards[t] + gamma * q_next - q_t

        # Update eligibility trace
        if trace_type == 'accumulating':
            # Decay all traces, then add current features
            for i in range(num_weights):
                z[i] *= gamma * lam
            for i in x_t:
                z[i] += 1.0
        else:  # replacing
            # Decay all traces, then set active features to 1
            for i in range(num_weights):
                z[i] *= gamma * lam
            for i in x_t:
                z[i] = 1.0

        # Update weights
        for i in range(num_weights):
            w[i] += alpha * delta * z[i]

    return w.tolist()
